class Solution {
public:
    bool checkPossibility(vector<int>& a) {
        int cnt=0;
        for(int i=1;i<(int)a.size();i++){
            if(a[i]<a[i-1]){
                if(++cnt>1) return false;
                if(i>=2&&a[i]<a[i-2]) a[i]=a[i-1]; else a[i-1]=a[i];
            }
        }
        return true;
    }
};
